def max_length(sublists):
    if not sublists:
        return (0, []):
    max_len = 0
    max_sublist = []
    for sub in sublists:
        current_len = len(sub)
        if current_len > max_len:
            max_len = current_len
            max_sublist = sub
    return (max_len, max_sublist)
